window.__QUIZ_DATA__=[{"id":"theory>Computer Studies>2025>1>a>i","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"i","group":"FINAL","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).      Identify the parts labelled:  X;","images":["data:image/jpeg;base64,"],"marking_scheme":"Optical Disc Drive (DVD/CD Drive)","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>1>a>ii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"ii","group":"FINAL","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).    Identify the parts labelled:  Y;","images":["data:image/jpeg;base64,"],"marking_scheme":"Power Button","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>1>a>iii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"iii","group":"FINAL","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).    Identify the parts labelled:  Z.","images":["data:image/jpeg;base64,"],"marking_scheme":"USB Ports","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>1>b>i","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).    State one use of the parts labelled:  X;","images":["data:image/jpeg;base64,"],"marking_scheme":"1. Installing software/operating systems: Many software programs and operating systems (like Windows, Linux distributions) are distributed on CDs or DVDs. The optical drive is used to read these discs for installation.    2. Playing audio CDs: Users can insert music CDs into the drive to play audio.    3. Watching movies/videos: DVD drives (and Blu-ray drives, which are also optical drives) allow users to play movie DVDs or Blu-ray discs.    4. Burning/writing data to discs: Many optical drives are \"writers\" (e.g., DVD-RW, CD-RW). This allows users to save or backup their own data (documents, photos, videos) onto blank recordable CDs or DVDs.    5. Data backup and archival: For long-term archival or offline backup of less frequently accessed data, burning it to a disc can be a convenient method, especially for sharing physical copies.","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>1>b>ii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).    State one use of the parts labelled:  Y;","images":["data:image/jpeg;base64,"],"marking_scheme":"1. Turning the computer ON: The primary and most common use is to initiate the boot-up process of the computer.    2. Turning the computer OFF (graceful shutdown): A single, brief press of the power button (if configured in the operating system's power options) can initiate a graceful shutdown process, allowing the OS to close programs and save data before powering down.    3. Putting the computer to SLEEP/HIBERNATE: Similar to shutdown, a brief press can often be configured to put the computer into a low-power sleep mode or hibernate mode, allowing for a quicker resume.    4. Forced shutdown (long press): If the computer is unresponsive or frozen, pressing and holding the power button for several seconds (typically 4-10 seconds) will force a hard shutdown, cutting power directly. This should be used as a last resort to avoid potential data loss or system file corruption.","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>1>b>iii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).    State one use of the parts labelled:  Z.","images":["data:image/jpeg;base64,"],"marking_scheme":"1. Connecting peripheral devices: USB ports are universally used to connect a wide variety of peripheral devices to the computer, such as keyboards, mice, printers, scanners, webcams, and external hard drives.    2. Transferring data: They allow for the transfer of data between the computer and removable storage devices like USB flash drives (thumb drives), external hard drives, and memory card readers.    3. Charging devices: Many modern USB ports (especially USB 3.0 or higher, and specific charging ports) can provide power to charge mobile phones, tablets, smartwatches, and other USB-powered gadgets.    4. Connecting networking adapters: USB Wi-Fi adapters or Ethernet adapters can be plugged into USB ports to provide network connectivity to computers that lack built-in options or need an alternative.    5. Connecting audio devices: USB headphones, microphones, and external sound cards can be connected for audio input and output.","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>1>c","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"COMPUTER HARDWARE : CENTRAL PROCESSING UNIT","question":"The diagram in Figure 1 is the system unit of a computer. Use it to answer questions 1(a) to 1(c).    List four internal components of the system unit shown in Figure 1.","images":["data:image/jpeg;base64,"],"marking_scheme":"1. Motherboard: This is the main circuit board that connects all other components of the computer.    2. Central Processing Unit (CPU): Often called the \"brain\" of the computer, it performs most of the processing.    3. Random Access Memory (RAM): This is volatile memory used to temporarily store data that the CPU is actively using, allowing for quick access.    4. Hard Disk Drive (HDD) or Solid State Drive (SSD): These are long-term storage devices where the operating system, applications, and user files are permanently stored.    5. Power Supply Unit (PSU): Converts AC power from the wall outlet into DC power needed by the computer components.    6. Graphics Processing Unit (GPU) / Video Card: Processes and renders images, videos, and animations, sending them to the display. Can be integrated into the CPU or a separate dedicated card.    7. Cooling System (CPU cooler, case fans): Components like the CPU and GPU generate a lot of heat, and cooling systems (heatsinks, fans, liquid coolers) are essential to dissipate this heat and prevent overheating.    8. Network Interface Card (NIC): Allows the computer to connect to a network (wired via Ethernet or wireless via Wi-Fi). Often integrated into the motherboard.","marks":"4","difficulty":"2"},{"id":"theory>Computer Studies>2025>2>a","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"COMPUTER APPLICATION : WORD PROCESSING","question":"What is word processing?","images":[],"marking_scheme":"Word processing is the use of a computer program to create, edit, format, store, and print text-based documents. It allows users to type and modify written content easily, with features like spell check, text alignment, font styling, and inserting images or tables.    Examples of word processing software include:    - Microsoft Word    - Google Docs    - LibreOffice Writer    Word processing is commonly used for writing letters, reports, memos, essays, and other types of documents.","marks":"2","difficulty":"1"},{"id":"theory>Computer Studies>2025>2>b>i","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"COMPUTER APPLICATION : WORD PROCESSING","question":"Explain the following features of MS Word:    Watermark;","images":[],"marking_scheme":"Watermark in MS Word is a faint design, image, or text that appears behind the main content of a document, typically on every page. It is often used to indicate the status of a document (e.g., \"Confidential,\" \"Draft,\" or \"Sample\") or to add a subtle branding or decorative element.","marks":"2","difficulty":"1"},{"id":"theory>Computer Studies>2025>2>b>ii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"COMPUTER APPLICATION : WORD PROCESSING","question":"Explain the following features of MS Word:  Thesaurus;","images":[],"marking_scheme":"The Thesaurus in MS Word is a built-in reference tool that helps users find synonyms (words with similar meanings) and antonyms (opposites) for selected words. It enhances writing by improving word choice, avoiding repetition, and refining tone.","marks":"2","difficulty":"2"},{"id":"theory>Computer Studies>2025>2>b>iii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"COMPUTER APPLICATION : WORD PROCESSING","question":"Explain the following features of MS Word:  Drop cap;","images":[],"marking_scheme":"A Drop Cap is a typographic styling feature in Microsoft Word (and other desktop publishing and word processing applications) where the first letter (or sometimes the first few letters) of a paragraph is significantly enlarged and \"drops\" down into two or more lines of text below it.    It's a decorative element primarily used for visual appeal and to draw the reader's eye to the beginning of a section or chapter, commonly seen in:    - Books and magazines: Often used to mark the start of a new chapter or an important article.    - Newspapers: Can be used for lead articles or special features.    - Newsletters and brochures: To add a touch of classic design.","marks":"2","difficulty":"2"},{"id":"theory>Computer Studies>2025>2>b>iv","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"iv","group":"","topic":"COMPUTER APPLICATION : WORD PROCESSING","question":"Explain the following features of MS Word:  Find and Replace.","images":[],"marking_scheme":"Find and Replace is a feature in MS Word that allows users to quickly locate specific text within a document and automatically replace it with different text. It's useful for editing, updating repeated content, or correcting mistakes throughout a document.    Find  - Used to search for a word, phrase, number, or formatting in the document.  - Helps navigate to the exact locations where the searched item appears.    Replace  - Allows you to substitute the found text with a new one.  - You can replace one at a time or replace all occurrences in a single action.    Common Uses:  - Correcting spelling errors (e.g., change \"recieve\" to \"receive\").  - Updating names, dates, or repeated terms.  - Replacing formatting (like changing all bold text to italics).    How to Use:  1. Press Ctrl + H (shortcut for Find and Replace).  2. In the Find what box, type the text to search for.  3. In the Replace with box, type the new text.  4. Click Find Next, then Replace or Replace All.    This tool greatly increases efficiency, especially when working with large documents.","marks":"2","difficulty":"1"},{"id":"theory>Computer Studies>2025>3>a","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"COMPUTER HARDWARE : INPUT DEVICES","question":"Describe the computer keyboard.","images":[],"marking_scheme":"A computer keyboard is an input device used to enter data, commands, and text into a computer. It consists of a set of keys that include letters, numbers, symbols, and special function keys.","marks":"2","difficulty":"1"},{"id":"theory>Computer Studies>2025>3>b","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"COMPUTER HARDWARE : INPUT DEVICES","question":"List four types of key on a computer keyboard.","images":[],"marking_scheme":"1. Alphanumeric (Typing) Keys: These are the most numerous keys and include letters (A-Z), numbers (0-9), and punctuation marks (e.g., period, comma, question mark). This is where most text input occurs.    2. Function Keys: Labeled F1 through F12 (and sometimes F13-F24), these keys perform specific functions depending on the software application currently in use. For example, F1 often opens help, F5 refreshes a web page, and Alt+F4 closes a window.    3. Modifier (Control) Keys: These keys are used in combination with other keys to perform actions or shortcuts. Common modifier keys include:  - Ctrl (Control)  - Alt (Alternate)  - Shift  - Windows key (or Command key on Apple keyboards)    4. Navigation (Cursor Control) Keys: These keys allow you to move the cursor within a document or browse through content. They include:  - Arrow keys (Up, Down, Left, Right)  - Home  - End  - Page Up  - Page Down  - Insert  - Delete    5. Numeric Keypad: Usually located on the right side of a full-sized keyboard, this section contains numbers (0-9), arithmetic operators (+, -, *, /), and a decimal point, organized like a calculator for quick numerical data entry. It often has a \"Num Lock\" key to toggle its function.    6. Special Purpose/System Keys: These keys perform specific system-level functions:  - Esc (Escape): Often used to cancel an operation or exit a menu.  - Tab: Used to move the cursor a fixed number of spaces or to navigate between fields in a form.  - Caps Lock: Toggles typing in all uppercase letters.  - Enter/Return: Used to confirm commands, create new paragraphs, or submit data.  - Backspace: Deletes characters to the left of the cursor.  - Print Screen (PrtSc): Captures the current screen image.  - Scroll Lock: A legacy key, sometimes used for specific scrolling functions.  - Pause/Break: Another legacy key with limited modern use.","marks":"4","difficulty":"2"},{"id":"theory>Computer Studies>2025>3>c>i","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"COMPUTER HARDWARE : INPUT DEVICES","question":"State the function of each of the following shortcut key combinations:    Shift + Delete;","images":[],"marking_scheme":"The function of the Shift + Delete shortcut key combination in Windows (and many other operating systems/applications) is to:    Permanently delete a selected file or folder, bypassing the Recycle Bin (or Trash).    When you use Shift + Delete, the item is not moved to a temporary holding area where it can be easily recovered. Instead, it is immediately removed from the file system's index, making it much harder to recover. This action is generally irreversible without specialized data recovery software.","marks":"1","difficulty":"2"},{"id":"theory>Computer Studies>2025>3>c>ii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"COMPUTER HARDWARE : INPUT DEVICES","question":"State the function of each of the following shortcut key combinations:  Alt + F4.","images":[],"marking_scheme":"The function of the Alt + F4 shortcut key combination is:    To close the currently active window or program.    - If an application is active, pressing Alt + F4 will attempt to close that application. If there are unsaved changes, the application will usually prompt the user to save before closing.    - If no application window is active (i.e., you are on the desktop), pressing Alt + F4 will open the \"Shut Down Windows\" dialog box, allowing you to choose to shut down, restart, sleep, or switch users.","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>3>d>i","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"i","group":"FINAL","topic":"COMPUTER HARDWARE : INPUT DEVICES","question":"Name the shortcut key combination for performing the following tasks:    Highlighting an entire text in a document;","images":[],"marking_scheme":"The shortcut key combination to highlight (select) an entire text in a document is:    Ctrl + A","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>3>d>ii","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"ii","group":"FINAL","topic":"COMPUTER HARDWARE : INPUT DEVICES","question":"Name the shortcut key combination for performing the following tasks:  Previewing a document before printing.","images":[],"marking_scheme":"The shortcut key combination for previewing a document before printing is:    Ctrl + P    (This opens the Print dialog, which usually includes a preview of the document.)","marks":"1","difficulty":"1"},{"id":"theory>Computer Studies>2025>4>a","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : ALGORITHM AND FLOWCHART","question":"Use flowcharting to illustrate the sum of three numbers.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"2"},{"id":"theory>Computer Studies>2025>4>b","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : ALGORITHM AND FLOWCHART","question":"Use flowcharting to illustrate the average of five numbers.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Computer Studies>2025>5","subject":"Computer Studies","year":"2025","type":"Theory","sub_label":"5","group":"","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE(PL)","question":"Write a program in QBASIC to calculate the total and average scores in five subjects taken by each of ten students in a class. The scores of the ten students should be read from the keyboard.","images":[],"marking_scheme":"10 CLS  20  30 FOR student = 1 TO 10  40 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;PRINT \"Enter scores for Student \"; student  50 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;total = 0  60  70 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;FOR subject = 1 TO 5  80 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;INPUT \"Enter score for subject \"; subject; \": \", score  90 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;total = total + score  100 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;NEXT subject  110  120 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;average = total / 5  130  140 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;PRINT \"Total score for Student \"; student; \" is \"; total  150 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;PRINT \"Average score for Student \"; student; \" is \"; average  160 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;PRINT  170 NEXT student  180  190 END","marks":"10","difficulty":"3"}];